   workspaceMode: normalizeWorkspaceMode(safe.workspaceMode),
   straddleChain: safe.straddleChain || null,
   straddleLoading: !!safe.straddleLoading,
   straddleError: String(safe.straddleError || ''),
   straddleSelectedSymbol: String(safe.straddleSelectedSymbol || ''),
   straddleDeskTab: STRADDLE_DESK_TABS.includes(String(safe.straddleDeskTab || '').toLowerCase()) ? String(safe.straddleDeskTab).toLowerCase() : DEFAULT.straddleDeskTab,
   straddleSettings: api.sanitizeOptionsAutoTradeSettings?.(safe.straddleSettings || globalThis.__fwdTradeDeskOptionsAutoSettings || {}) || null,
