    entry: mark,
    stopLoss: side === 'buy' ? mark * 0.7 : side === 'sell' ? mark * 1.3 : 0,
    takeProfit: side === 'buy' ? mark * 1.45 : side === 'sell' ? mark * 0.55 : 0,
    size: 1,
    sizeMode: 'contracts',
    orderType: 'market_order',
